  ('heelevel3-d0d1b9a2-moex-00450', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-f6c431ec', 'sub-heelevel3-d0d1b9a2-04', NULL, 'single_choice', '當社會所有人都一致投票贊成政府的某一項議案時，代表下列那一種狀況的發生？', '["投票前的現況必為柏瑞圖最適", "投票後的結果必為柏瑞圖最適", "柏瑞圖改善", "投票矛盾"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "44c10a6685c9", "answer_pdf_sha1": "b3991257716c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00451', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-f6c431ec', 'sub-heelevel3-d0d1b9a2-04', NULL, 'single_choice', '下列那些財貨具有消費的非排他性？', '["公共財（publicgoods）", "私有財（privategoods）", "共有資源（commonresources）", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "44c10a6685c9", "answer_pdf_sha1": "b3991257716c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00452', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-f6c431ec', 'sub-heelevel3-d0d1b9a2-04', NULL, 'single_choice', '根據寇斯定理，透過自願性協商以解決污染外部性問題時，有關產生外部性問題之財貨，其財產 權歸屬之敘述何者正確？', '["只可歸屬於污染者", "只可歸屬於被污染者", "必須經由民主投票決定", "歸屬於污染者或被污染者均可"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "44c10a6685c9", "answer_pdf_sha1": "b3991257716c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00453', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-f6c431ec', 'sub-heelevel3-d0d1b9a2-04', NULL, 'single_choice', '對於用課稅或減產補貼來矯正生產行為的負外部性，下列敘述何者正確？', '["用課稅所達成的社會最適數量大於用減產補貼所達成的社會最適數量", "用課稅所達成的社會最適數量小於用減產補貼所達成的社會最適數量", "用課稅所達成的社會最適數量等於用減產補貼所達成的社會最適數量", "兩者所達成的最適數量並不一定相同，故無法比較"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "44c10a6685c9", "answer_pdf_sha1": "b3991257716c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00454', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-f6c431ec', 'sub-heelevel3-d0d1b9a2-04', NULL, 'single_choice', '關於總量管制與交易制度的敘述，下列何者錯誤？', '["無論排放權如何歸屬，社會終將以最低成本達成既定的污染減量", "排放權交易的誘因終將使各廠商污染減量的邊際成本相同", "排放權的歸屬將引起廠商間所得重分配的效果", "污染減量成本低的廠商較有意願購買排放權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "44c10a6685c9", "answer_pdf_sha1": "b3991257716c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
